xpath.script:
                (function() {
                    var STORAGE_KEY = 'wl_page_agent_history';

                    // Inject CSS AFTER page-agent loads (so we win the cascade)
                    function injectCSS() {
                        if (document.getElementById('wl-pa-style')) return;
                        var style = document.createElement('style');
                        style.id = 'wl-pa-style';
                        style.textContent = `
[class*="_background_1tu05_"] {
    background: linear-gradient(135deg, rgba(90,8,14,0.97), rgba(122,12,20,0.97)) !important;
    border-radius: 12px !important;
    box-shadow: 0 8px 32px rgba(90,8,14,0.3) !important;
}
[class*="_historySectionWrapper_1tu05_"] { background: rgba(90,8,14,0.85) !important; }
[class*="_header_1tu05_"] { background: rgba(90,8,14,0.6) !important; }
[class*="_statusText_1tu05_"] { color: #f5c400 !important; font-weight: 600 !important; }
[class*="_indicator_1tu05_"] { background: #f5c400 !important; }
[class*="_inputSectionWrapper_1tu05_"] { background: rgba(253,251,245,0.95) !important; }
[class*="_taskInput_1tu05_"] {
    background: #fff !important; color: #1f1f1f !important;
    border: 1px solid #ddd !important; border-radius: 8px !important;
    font-size: 13px !important; padding: 8px 12px !important;
    font-family: Inter, -apple-system, sans-serif !important;
}
[class*="_taskInput_1tu05_"]:focus {
    border-color: #5a080e !important;
    box-shadow: 0 0 0 2px rgba(90,8,14,0.1) !important;
    outline: none !important;
}
[class*="_controlButton_1tu05_"]:not([class*="_stopButton"]) {
    background: rgba(245,196,0,0.15) !important;
    color: #f5c400 !important;
    border-radius: 6px !important;
}
                        `;
                        document.head.appendChild(style);
                    }

                    function fixText() {
                        var input = document.querySelector('[class*="_taskInput_1tu05_"]');
                        if (input && input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                            input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
                        }
                        var wrapper = document.querySelector('[class*="_wrapper_1tu05_"]');
                        if (!wrapper) return;
                        var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
                        var node;
                        while (node = walker.nextNode()) {
                            var t = node.textContent;
                            if (t.indexOf('\u51c6\u5907\u5c31\u7eea') >= 0) node.textContent = node.textContent.replace(/\u51c6\u5907\u5c31\u7eea/g, 'Siap');
                            if (t.indexOf('\u7b49\u5f85\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u7b49\u5f85\u4efb\u52a1[^\n]*/g, 'Menunggu tugas...');
                            if (t.indexOf('\u6b63\u5728\u601d\u8003') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u601d\u8003[^\n]*/g, 'Sedang berpikir...');
                            if (t.indexOf('\u6b63\u5728\u6267\u884c') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u6267\u884c[^\n]*/g, 'Sedang menjalankan...');
                            if (t.indexOf('\u4efb\u52a1\u5b8c\u6210') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5b8c\u6210/g, 'Tugas selesai');
                            if (t.indexOf('\u4efb\u52a1\u5df2\u505c\u6b62') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5df2\u505c\u6b62/g, 'Tugas dihentikan');
                            if (t.indexOf('\u51fa\u73b0\u9519\u8bef') >= 0) node.textContent = node.textContent.replace(/\u51fa\u73b0\u9519\u8bef/g, 'Terjadi kesalahan');
                        }
                    }

                    function setupAgent() {
                        var pa = window.pageAgent;
                        if (!pa || pa.disposed) return false;
                        try {
                            pa.config.language = 'id-ID';
                            if (pa.config.pageController && pa.config.pageController.config) {
                                pa.config.pageController.config.language = 'id-ID';
                            }
                        } catch(e) {}
                        try {
                            var saved = sessionStorage.getItem(STORAGE_KEY);
                            if (saved) {
                                var h = JSON.parse(saved);
                                if (Array.isArray(h) && h.length > 0) pa.history = h;
                            }
                        } catch(e) {}
                        try {
                            pa.addEventListener('message', function() {
                                try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
                            });
                        } catch(e) {}
                        window.addEventListener('beforeunload', function() {
                            try { if (pa.history && pa.history.length > 0) sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
                        });
                        return true;
                    }

                    // Wait for page-agent to load, then inject CSS + fix text
                    var attempts = 0;
                    var interval = setInterval(function() {
                        attempts++;
                        injectCSS();
                        fixText();
                        if (window.pageAgent && !window.pageAgent.disposed) setupAgent();
                        if (attempts >= 120) clearInterval(interval);
                    }, 500);

                    // MutationObserver: fix text on DOM changes (indefinite)
                    var observer = new MutationObserver(function() {
                        fixText();
                    });
                    if (document.body) {
                        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
                    }
                })();
